async (params, browser) => {
  // Open bookmarks
  await browser.open('https://x.com/i/bookmarks')

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract bookmarked tweets
  const bookmarks = await browser.evaluate(`const tweets = []; const articles = document.querySelectorAll('article[data-testid="tweet"]'); for (let i = 0; i < Math.min(articles.length, 15); i++) { const el = articles[i]; const userNameEl = el.querySelector('[data-testid="User-Name"]'); const tweetTextEl = el.querySelector('[data-testid="tweetText"]'); const timeEl = el.querySelector('time'); const linkEl = el.querySelector('a[href*="/status/"]'); tweets.push({ author: userNameEl ? userNameEl.textContent.trim() : 'Unknown', text: tweetTextEl ? tweetTextEl.textContent.trim() : '', time: timeEl ? timeEl.getAttribute('datetime') : '', url: linkEl ? 'https://x.com' + linkEl.getAttribute('href') : '' }); } return { count: tweets.length, tweets: tweets }`)

  return bookmarks
}
